-- ║  121: Seed NET KASA Historical Data (Jan–Mar 2026)                     ║
-- ║                                                                        ║
-- ║  Imports 3 months of accounting data from the legacy Excel system      ║
-- ║  into accounting_entries as manual_import records.                      ║
-- ║                                                                        ║
-- ║  Registers: USDT, NAKIT_TL, NAKIT_USD, TL_BANKA                       ║
-- ║  Periods:   2025-12, 2026-01, 2026-02, 2026-03                        ║
-- ║  Entries:   ~537 total (Jan ~203, Feb ~199, Mar ~135)                   ║
-- ╚══════════════════════════════════════════════════════════════════════════╝


-- ============================================================================
-- 0. Widen CHECK constraints on accounting_entries
--    Original schema (008) has currency IN ('TL','USD','USDT') and
--    register IN ('USDT','NAKIT_TL','NAKIT_USD','TRX').
--    We need TRY currency and TL_BANKA register for the imported data.
-- ============================================================================
ALTER TABLE public.accounting_entries
  DROP CONSTRAINT IF EXISTS accounting_entries_currency_check;
ALTER TABLE public.accounting_entries
  ADD CONSTRAINT accounting_entries_currency_check
    CHECK (currency IN ('TL', 'TRY', 'USD', 'USDT'));

ALTER TABLE public.accounting_entries
  DROP CONSTRAINT IF EXISTS accounting_entries_register_check;
ALTER TABLE public.accounting_entries
  ADD CONSTRAINT accounting_entries_register_check
    CHECK (register IN ('USDT', 'NAKIT_TL', 'NAKIT_USD', 'TL_BANKA', 'TRX'));


-- ============================================================================
-- 1. Seed data
-- ============================================================================
DO $$
DECLARE
  _org_id UUID;
BEGIN
  SELECT id INTO _org_id FROM public.organizations LIMIT 1;
  IF _org_id IS NULL THEN
    RAISE NOTICE 'No organization found, skipping NET KASA seed data';
    RETURN;
  END IF;

  -- ══════════════════════════════════════════════════════════════════════════
  -- JANUARY 2026 (OCAK) — ~203 entries
  -- ══════════════════════════════════════════════════════════════════════════



  -- ══════════════════════════════════════════════════════════════════════════
  -- FEBRUARY 2026 (ŞUBAT) — ~199 entries
  -- ══════════════════════════════════════════════════════════════════════════



  -- ══════════════════════════════════════════════════════════════════════════
  -- MARCH 2026 (MART) — ~135 entries
  -- ══════════════════════════════════════════════════════════════════════════


END $$;


